    ["Hide the + / - zoom buttons on the minimap. You can still mouse-wheel to zoom."] = "Die +/–-Zoom-Schaltflächen der Minimap ausblenden. Zoomen per Mausrad weiterhin möglich.",
    ["Hide the 1px accent border drawn around globally skinned frames."] = "Den 1px-Akzentrahmen um global angepasste Rahmen ausblenden.",
