    ["Hide the border outline entirely."] = "Den Rahmenumriss vollständig ausblenden.",
    ["Hide the buff frame entirely, even when hovering its anchor area."] = "Den Buff-Rahmen vollständig ausblenden, auch beim Hover über seinen Ankerbereich.",
    ["Hide the clockwise cooldown swipe animation drawn over %1$s icons. Duration text still works if it is enabled below."] = "Die Uhrzeiger-Abklingzeit-Wischanimation über %1$s-Symbolen ausblenden. Dauertext funktioniert weiterhin, wenn er unten aktiviert ist.",
    ["Hide the combat timer outside of boss encounters, M+ dungeons, and PvP matches. Off shows the timer on every pull."] = "Den Kampftimer außerhalb von Bosskämpfen, M+-Dungeons und PvP-Matches ausblenden. Ausgeschaltet zeigt den Timer bei jedem Kampf.",
    ["Hide the compact raid frame manager widget that lets you pick built-in raid profiles."] = "Das kompakte Schlachtzug-Frame-Manager-Widget zum Auswählen von Schlachtzugprofilen ausblenden.",
    ["Hide the cooldown swipe animation drawn over icons."] = "Die Abklingzeit-Wischanimation über Symbolen ausblenden.",
    ["Hide the cooldown swipe animation that fills the icon as time expires."] = "Die Abklingzeit-Wischanimation, die das Symbol beim Ablauf füllt, ausblenden.",
    ["Hide the counter while in the open world. Useful if you only need it for instanced content."] = "Den Zähler in der offenen Welt ausblenden. Nützlich, wenn er nur für Instanzinhalte benötigt wird.",
    ["Hide the crafting/work order notification icon on the minimap."] = "Das Handwerk-/Arbeitsauftrags-Benachrichtigungssymbol auf der Minimap ausblenden.",
    ["Hide the debuff frame entirely, even when hovering its anchor area."] = "Den Debuff-Rahmen vollständig ausblenden, auch beim Hover über seinen Ankerbereich.",
    ["Hide the decorative Blizzard artwork around this button while keeping the button itself visible."] = "Dekorative Blizzard-Grafik um diese Taste ausblenden, während die Taste selbst sichtbar bleibt.",
    ["Hide the default Blizzard prey indicator so only the QUI tracker is shown."] = "Den Standard-Blizzard-Beuteindikator ausblenden, sodass nur der QUI-Tracker angezeigt wird.",
    ["Hide the display while in the open world. Useful if you only care about raid buffs inside instances."] = "Die Anzeige in der offenen Welt ausblenden. Nützlich, wenn Schlachtzug-Buffs nur in Instanzen relevant sind.",
    ["Hide the drawer toggle button until you mouse over the minimap."] = "Die Ablage-Umschalttaste ausblenden, bis du mit der Maus über die Minimap fährst.",
    ["Hide the duration and spell-name text on every bar in this container."] = "Dauer- und Zaubernamen-Text auf allen Leisten in diesem Container ausblenden.",
    ["Hide the duration countdown text on every icon in this row. The swipe animation still plays."] = "Den Dauer-Countdown-Text auf allen Symbolen in dieser Reihe ausblenden. Die Wischanimation läuft weiterhin.",
    ["Hide the entire bar while you are in combat."] = "Die gesamte Leiste im Kampf ausblenden.",
    ["Hide the experience and reputation bars while you are in a pet battle."] = "Erfahrungs- und Rufleisten während eines Haustierkampfes ausblenden.",
    ["Hide the experience and reputation bars while you are riding a vehicle."] = "Erfahrungs- und Rufleisten während der Fahrzeugnutzung ausblenden.",
