    ["Hide the label and show only the value."] = "Beschriftung ausblenden und nur den Wert anzeigen.",
    ["Hide the label text under/beside the icon row for a more compact display."] = "Den Beschriftungstext unter/neben der Symbolreihe für eine kompaktere Anzeige ausblenden.",
    ["Hide the mail notification icon on the minimap. Requires a UI reload to take effect."] = "Das Post-Benachrichtigungssymbol auf der Minimap ausblenden. Erfordert UI-Neustart.",
    ["Hide the missing raid buffs display when you aren't in a party or raid."] = "Die Anzeige fehlender Schlachtzug-Buffs ausblenden, wenn du nicht in einer Gruppe oder einem Schlachtzug bist.",
    ["Hide the native Blizzard minimap border artwork at the top of the minimap."] = "Das native Blizzard-Minimap-Rahmengrafik oben ausblenden.",
    ["Hide the numeric countdown on this spell's icon/bar only, while leaving other spells in the container unchanged."] = "Den numerischen Countdown nur auf diesem Zaubersymbol/dieser Leiste ausblenden, andere Zauber im Container unverändert lassen.",
    ["Hide the objective tracker while you are in a Battleground."] = "Den Zieltracker auf Schlachtfeldern ausblenden.",
