    ["Render layer for the pet unit frame."] = "Renderebene für den Begleiter-Einheitenrahmen.",
    ["Render layer for the player castbar. Raise this if your castbar is being hidden behind other HUD elements."] = "Renderebene für die Spieler-Zauberwirkleiste. Erhöhen, wenn die Zauberwirkleiste hinter anderen HUD-Elementen versteckt wird.",
    ["Render layer for the player unit frame. Higher values draw over lower-layered HUD elements."] = "Renderebene für den Spieler-Einheitenrahmen. Höhere Werte werden über niedrigere HUD-Elemente gerendert.",
    ["Render layer for the primary resource bar (mana, rage, energy, etc.). Higher values draw over lower-layered HUD elements."] = "Renderebene für die primäre Ressourcenleiste (Mana, Wut, Energie usw.). Höhere Werte werden über niedrigere HUD-Elemente gerendert.",
    ["Render layer for the secondary resource bar (combo points, holy power, soul shards, etc.)."] = "Renderebene für die sekundäre Ressourcenleiste (Kombo-Punkte, Heilige Kraft, Seelensplitter usw.).",
    ["Render layer for the skyriding vigor and dynamic flight HUD shown while mounted."] = "Renderebene für die Himmelsreiten-Vitalität und den Dynamischen-Flug-HUD beim Reiten.",
    ["Render layer for the target castbar. Raise this to keep enemy casts visible above other HUD elements."] = "Renderebene für die Ziel-Zauberwirkleiste. Erhöhen, damit feindliche Zauber über anderen HUD-Elementen sichtbar bleiben.",
    ["Render layer for the target of target frame."] = "Renderebene für den Ziel-des-Ziels-Rahmen.",
