    ["Render the duration and spell-name text on vertical bars. Turn off for icon-only vertical bars."] = "Dauer und Zaubernamenstext auf vertikalen Leisten anzeigen. Deaktivieren für nur Symbole enthaltende vertikale Leisten.",
    ["Render the zone label in all uppercase letters."] = "Das Zonenbezeichnung in Großbuchstaben anzeigen.",
