    ["Size Override"] = "Größenüberschreibung",
    ["Size multiplier for Autocast Shine."] = "Größenmultiplikator für Auto-Zaubern-Glanz.",
    ["Size multiplier for the Autocast Shine glow."] = "Größenmultiplikator für den Auto-Zaubern-Glanz.",
    ["Size of the Second Wind pips (Pips mode only)."] = "Größe der Zweiter-Wind-Punkte (nur Punkte-Modus).",
    ["Size of the particles in the AutoCast glow style."] = "Größe der Partikel im AutoCast-Leucht-Stil.",
