    ["Skin Game Menu (Req. Reload)"] = "Spielmenü skinnen (Neuladen erforderlich)",
    ["Skin Loot Window (Req. Reload)"] = "Beutefenster skinnen (Neuladen erforderlich)",
    ["Skin Objective Tracker"] = "Ziel-Tracker skinnen",
    ["Skin Ready Check Frame"] = "Bereitschaftsprüfungs-Rahmen skinnen",
    ["Skin Roll Frames (Req. Reload)"] = "Würfelrahmen skinnen (Neuladen erforderlich)",
    ["Skin StaticPopup confirmation dialogs. Requires a reload."] = "StaticPopup-Bestätigungsdialoge skinnen. Erfordert ein Neuladen.",
