    ["Support"] = "Support",
    ["Supports SharedMedia textures. Install the SharedMedia addon to add your own."] = "Unterstützt SharedMedia-Texturen. Das SharedMedia-Addon installieren, um eigene hinzuzufügen.",
    ["Suppress all cooldown effects (swipe, overlay, flash) for this container, even on Blizzard-managed elements driven by the same icons."] = "Alle Abklingzeit-Effekte (Wischanimation, Overlay, Blitz) für diesen Container unterdrücken, auch bei Blizzard-verwalteten Elementen, die von denselben Symbolen gesteuert werden.",
    ["Suppress all tooltips while you're in combat. Use the modifier key below to force-show them when needed."] = "Alle Tooltips während des Kampfes unterdrücken. Die Modifikator-Taste unten verwenden, um sie bei Bedarf erzwungenermaßen anzuzeigen.",
    ["Suppress entitlement and recruit-a-friend delivery toast notifications."] = "Berechtigung- und Freunde-werben-Lieferungsbenachrichtigungs-Toasts unterdrücken.",
    ["Suppress general event toast popups, often triggered by campaign progress or housing updates."] = "Allgemeine Ereignis-Toast-Popups unterdrücken, die oft durch Kampagnenfortschritt oder Haus-Aktualisierungen ausgelöst werden.",
    ["Suppress the blocking static popups that appear for housing-related confirmations."] = "Die blockierenden statischen Popups unterdrücken, die für hausbezogene Bestätigungen erscheinen.",
    ["Suppress the blocking static popups that appear for talent-related confirmations."] = "Die blockierenden statischen Popups unterdrücken, die für talenbbezogene Bestätigungen erscheinen.",
    ["Suppress the glow animation on every microbutton (collections, achievements, etc.) when new items are detected."] = "Die Glühanimation auf jeder Mikro-Schaltfläche (Sammlungen, Erfolge usw.) unterdrücken, wenn neue Elemente erkannt werden.",
    ["Suppress the pulsing reminder on the talent microbutton that appears when unspent points are available."] = "Die pulsierende Erinnerung auf der Talent-Mikro-Schaltfläche unterdrücken, die erscheint, wenn ungenutzte Punkte verfügbar sind.",
    ["Suppress the red error messages printed above the action bar, such as Not Enough Mana or Spell Not Ready."] = "Die roten Fehlermeldungen über der Aktionsleiste unterdrücken, wie Nicht genug Mana oder Zauber nicht bereit.",
    ["Suppress the toast that pops when you acquire a new cosmetic item."] = "Den Toast unterdrücken, der erscheint, wenn du ein neues kosmetisches Item erhältst.",
    ["Suppress the toast that pops when you learn a new battle pet."] = "Den Toast unterdrücken, der erscheint, wenn du ein neues Kampfbegleiter-Tier lernst.",
    ["Suppress the toast that pops when you learn a new mount."] = "Den Toast unterdrücken, der erscheint, wenn du ein neues Reittier lernst.",
    ["Suppress the toast that pops when you learn a new toy."] = "Den Toast unterdrücken, der erscheint, wenn du ein neues Spielzeug lernst.",
    ["Suppress the tutorial help tip callouts that Blizzard shows near talent and spellbook buttons."] = "Die Tutorial-Hilfehinweise unterdrücken, die Blizzard nahe Talent- und Zauberbuch-Schaltflächen anzeigt.",
    ["Suppress the yellow info messages printed above the action bar, such as quest objective progress updates."] = "Die gelben Infomeldungen über der Aktionsleiste unterdrücken, wie Quest-Ziel-Fortschrittsaktualisierungen.",
