    ["Swap the vigor bar color while Thrill of the Skies is active so the buff state is obvious."] = "Die Vitalitätsleisten-Farbe tauschen, während 'Nervenkitzel des Himmels' aktiv ist, damit der Buff-Zustand offensichtlich ist.",
    ["Swap to Primary Position"] = "Zur primären Position wechseln",
    ["Sweep the GCD during instant melee swings, not just during spell casts."] = "Den GCD während sofortiger Nahkampf-Schwünge wischen, nicht nur während Zauberwirkungen.",
    ["Swipe Custom Color"] = "Benutzerdefinierte Wischanimations-Farbe",
