    ["Truncate the dungeon name to this many characters. Set to 0 to show the full name."] = "Den Dungeon-Namen auf diese Anzahl von Zeichen kürzen. Auf 0 setzen, um den vollständigen Namen anzuzeigen.",
    ["Try different keywords"] = "Andere Suchbegriffe versuchen",
    ["Try importing the QUI Edit Mode layout string from the Welcome tab, then /rl. If frames are still missing, check for Lua errors with /console scriptErrors 1 and report them on GitHub or Discord."] = "Versuche, den QUI-Bearbeitungsmodus-Layout-String vom Willkommen-Tab zu importieren, dann /rl. Wenn Rahmen noch fehlen, auf Lua-Fehler mit /console scriptErrors 1 prüfen und sie auf GitHub oder Discord melden.",
    ["Turn on combat logging automatically when a Mythic+ run starts, and off when it ends."] = "Kampfprotokollierung automatisch einschalten, wenn ein Mythisch+-Run beginnt, und ausschalten, wenn er endet.",
    ["Turn on combat logging automatically when you zone into a raid instance."] = "Kampfprotokollierung automatisch einschalten, wenn du eine Schlachtzugsinstanz betrittst.",
    ["Type"] = "Typ",
    ["Type "] = "Typ ",
    ["Type a buff/debuff name or numeric Spell ID in the search box above. Numeric IDs are resolved as auras for this bar."] = "Einen Buff/Debuff-Namen oder eine numerische Zauber-ID in das Suchfeld oben eingeben. Numerische IDs werden als Auren für diese Leiste aufgelöst.",
