    ["Use a per-spell bar color for this aura-bar spell instead of the container's default bar color."] = "Eine zaubersbezifische Leistenfarbe für diesen Aura-Leisten-Zauber verwenden, anstatt der Standard-Leistenfarbe des Containers.",
    ["Use abbreviated distance labels (e.g., Melee/Close/Far) instead of longer phrasing."] = "Abgekürzte Entfernungsbezeichnungen verwenden (z.B. Nahkampf/Nah/Fern) anstatt längerer Formulierungen.",
    ["Use green/yellow/red time-based duration colors instead of the static text color."] = "Grün/Gelb/Rot zeitbasierte Dauerfarben verwenden, anstatt der statischen Textfarbe.",
    ["Use the Frame Positioning tab to fine-tune frame positions relative to each other."] = "Den Tab Rahmenpositionierung verwenden, um Rahmenpositionen relativ zueinander fein abzustimmen.",
    ["Use the Nudge tool for fine-grained pixel adjustments to any anchored element."] = "Das Nudge-Werkzeug für feinkörnige Pixel-Anpassungen an verankerten Elementen verwenden.",
