    ["Width and height for each %1$s frame."] = "Breite und Höhe für jeden %1$s-Rahmen.",
    ["Width of each Spotlight frame in pixels."] = "Breite jedes Spotlight-Rahmens in Pixeln.",
    ["Width of each bar in pixels. Ignored when Auto Width From Anchor is on."] = "Breite jeder Leiste in Pixeln. Ignoriert, wenn 'Auto-Breite vom Anker' aktiviert ist.",
    ["Width of each party frame in pixels."] = "Breite jedes Gruppenrahmens in Pixeln.",
    ["Width of each pet frame in pixels."] = "Breite jedes Begleiter-Rahmens in Pixeln.",
    ["Width of the bar in pixels."] = "Breite der Leiste in Pixeln.",
    ["Width of the bar in pixels. Ignored when Auto Attach matches the player frame width."] = "Breite der Leiste in Pixeln. Ignoriert, wenn Auto-Anheften der Spielerrahmen-Breite entspricht.",
    ["Width of the prey tracker bar in pixels."] = "Breite der Beute-Tracker-Leiste in Pixeln.",
    ["Width of the tracking bar as a percentage of its default width."] = "Breite der Tracking-Leiste als Prozentsatz ihrer Standardbreite.",
    ["Width of this custom datapanel in pixels."] = "Breite dieses benutzerdefinierten Datenpanels in Pixeln.",
    ["Window"] = "Fenster",
    ["Window "] = "Fenster ",
