    ["Window 1 (primary)"] = "Fenster 1 (primär)",
    ["Window Background"] = "Fenster-Hintergrund",
    ["Window border color. (Default: QUI accent.)"] = "Fenster-Rahmen-Farbe. (Standard: QUI-Akzent.)",
    ["Windows"] = "Fenster",
    ["Wipe and rebuild every CDM cache. Out-of-combat only. Run when /qui cdm_cache status reports stale state."] = "Jeden CDM-Cache löschen und neu aufbauen. Nur außerhalb des Kampfes. Ausführen, wenn /qui cdm_cache status einen veralteten Zustand meldet.",
